const t={boardTopology:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Observa cómo se conectan las placas de control de tu impresora: el host (SBC) y cada MCU con el que se comunica, con el tipo de cada conexión y una estimación de la placa o chip lo más precisa posible, leída en vivo desde la configuración."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Ayuda"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Acerca de la topología de placas"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Cerrar"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Cómo interpretarlo"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"El host (tu SBC, por ejemplo una Raspberry Pi o CB1) se sitúa arriba."}},{t:0,b:{t:2,i:[{t:3}],s:"Cada tarjeta de MCU muestra cómo se conecta (USB / CAN bus / UART) y su chip."}},{t:0,b:{t:2,i:[{t:3}],s:"Aparece una estimación de la placa cuando el identificador de conexión coincide con una placa conocida."}}],topics:{mcus:{title:{t:0,b:{t:2,i:[{t:3}],s:"MCUs"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Un MCU es una placa microcontroladora que controla motores, calentadores y sensores. Una impresora tiene al menos uno (la placa base); muchas añaden una placa de cabezal y a veces una placa de sonda o de LED. Este panel lista cada sección `[mcu]` que tiene Klipper."}}},connections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Tipos de conexión"}},body:{t:0,b:{t:2,i:[{t:3}],s:"USB — un enlace serie sobre USB (la conexión habitual de la placa base). CAN bus — un bus compartido de dos hilos, común para placas de cabezal. UART — un enlace serie directo por GPIO. El tipo se infiere de los ajustes `serial` / `canbus_uuid` de cada MCU."}}},detection:{title:{t:0,b:{t:2,i:[{t:3}],s:"Cómo funciona la detección"}},body:{t:0,b:{t:2,i:[{t:3}],s:'El chip y la placa se estiman comparando el identificador de conexión (la ruta serial o el UUID de CAN) con una tabla de patrones. Una estimación de placa muestra una confianza de coincidencia; cuando nada coincide, el chip/placa aparece como "desconocido", aunque la conexión en sí se sigue mostrando.'}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glosario"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{mcu:{term:{t:0,b:{t:2,i:[{t:3}],s:"MCU"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Unidad microcontroladora — una placa de control que ejecuta el firmware de Klipper (placa base, cabezal, etc.)."}}},canbus:{term:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un bus compartido de dos hilos que enlaza placas mediante un UUID único — popular para el cableado del cabezal."}}},host:{term:{t:0,b:{t:2,i:[{t:3}],s:"Host / SBC"}},def:{t:0,b:{t:2,i:[{t:3}],s:"El ordenador de placa única (Pi, CB1, …) que ejecuta Klipper y se comunica con los MCUs."}}}}},host:{label:{t:0,b:{t:2,i:[{t:3}],s:"Host"}},role:{t:0,b:{t:2,i:[{t:3}],s:"Ordenador de placa única — ejecuta Klipper"}}},mcu:{chip:{t:0,b:{t:2,i:[{t:3}],s:"Chip"}},board:{t:0,b:{t:2,i:[{t:3}],s:"Placa"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"desconocido"}},identifier:{t:0,b:{t:2,i:[{t:3}],s:"Identificador"}},confidence:{t:0,b:{t:2,i:[{t:4,k:"pct"},{t:3,v:"% de coincidencia"}]}},viewBoard:{t:0,b:{t:2,i:[{t:3}],s:"Ver detalles de la placa"}},hideBoard:{t:0,b:{t:2,i:[{t:3}],s:"Ocultar detalles"}}},conn:{canbus:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},usb:{t:0,b:{t:2,i:[{t:3}],s:"USB"}},uart:{t:0,b:{t:2,i:[{t:3}],s:"UART"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"desconocido"}},via:{t:0,b:{t:2,i:[{t:3,v:"vía "},{t:4,k:"type"}]}}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" MCUs"}]}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Leyendo la topología…"}},unreachable:{t:0,b:{t:2,i:[{t:3}],s:"No se pudo conectar con la impresora."}},empty:{t:0,b:{t:2,i:[{t:3}],s:"No se encontraron MCUs en la configuración."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Reintentar"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Actualizar"}}},board:{suggested:{t:0,b:{t:2,i:[{t:3}],s:"sugerido"}},ports:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" puertos"}]}},specsTitle:{t:0,b:{t:2,i:[{t:3}],s:"Especificaciones"}},portsTitle:{t:0,b:{t:2,i:[{t:3}],s:"Puertos"}},none:{t:0,b:{t:2,i:[{t:3}],s:"Aún no hay detalles de catálogo para esta placa."}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Cargando placa…"}}}}};export{t as default};
